@app.route('/resource', methods=['GET'])
def get_resource():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({"error": "unauthorized", "error_description": "Missing or invalid Authorization header"}), 401

    token = auth_header.split(' ')[1]
    token_data = access_tokens.get(token)

    if not token_data or token_data["expires_at"] < datetime.utcnow():
        return jsonify({"error": "invalid_token", "error_description": "Access token is invalid or expired"}), 401

    # Token is valid, return the protected resource
    return jsonify({
        "message": f"Hello, {token_data['user_id']}! You accessed a protected resource.",
        "client_id": token_data['client_id'],
        "scope": token_data['scope']
    })


